namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Code { get; set; } = string.Empty;
    public string Name { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public int DepartmentId { get; set; }
    public string CourseCode { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string InstructorName { get; set; } = string.Empty;
    public string InstructorBio { get; set; } = string.Empty;
    public bool IsFeatured { get; set; }
}

using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Full name is required.")]
    [StringLength(100)]
    public string FullName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^[A-Z0-9]{6,10}$", ErrorMessage = "Student ID must be 6–10 alphanumeric characters.")]
    public string StudentId { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CourseCatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;

    public CourseCatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Code = "CS", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Code = "MATH", Name = "Mathematics", Description = "Pure and applied mathematics courses." },
            new() { Id = 3, Code = "ENG", Name = "English", Description = "Literature, writing, and language studies." },
            new() { Id = 4, Code = "PHYS", Name = "Physics", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 5, Code = "HIST", Name = "History", Description = "Exploration of past events, civilizations, and cultures." },
        };

        _courses = new List<Course>
        {
            new() { Id = 1, DepartmentId = 1, CourseCode = "CS101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using Python. Topics include variables, control flow, functions, and basic data structures.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen holds a PhD in Computer Science from MIT and has 15 years of teaching experience in introductory programming.", IsFeatured = true },
            new() { Id = 2, DepartmentId = 1, CourseCode = "CS201", Title = "Data Structures & Algorithms", Description = "Study of fundamental data structures (trees, graphs, hash tables) and algorithm design techniques including divide-and-conquer, dynamic programming, and greedy algorithms.", Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", InstructorName = "Dr. James Park", InstructorBio = "Dr. Park is a former software engineer at Google with research interests in algorithm optimization and competitive programming.", IsFeatured = true },
            new() { Id = 3, DepartmentId = 1, CourseCode = "CS310", Title = "Database Systems", Description = "Relational database design, SQL, normalization, transaction management, and introduction to NoSQL databases.", Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", InstructorName = "Dr. Maria Lopez", InstructorBio = "Dr. Lopez specializes in distributed databases and has published extensively on query optimization techniques." },
            new() { Id = 4, DepartmentId = 1, CourseCode = "CS450", Title = "Machine Learning", Description = "Supervised and unsupervised learning, neural networks, support vector machines, and practical applications of ML in real-world scenarios.", Credits = 4, Schedule = "Tue/Thu 1:00–2:20 PM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen holds a PhD in Computer Science from MIT and has 15 years of teaching experience in introductory programming.", IsFeatured = true },
            new() { Id = 5, DepartmentId = 2, CourseCode = "MATH101", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics and engineering problems.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Prof. Robert Kim", InstructorBio = "Prof. Kim is an award-winning educator with over 20 years of experience making calculus accessible to all students." },
            new() { Id = 6, DepartmentId = 2, CourseCode = "MATH201", Title = "Linear Algebra", Description = "Vector spaces, linear transformations, matrices, determinants, eigenvalues, and applications.", Credits = 3, Schedule = "Tue/Thu 9:00–10:20 AM", InstructorName = "Dr. Elena Rossi", InstructorBio = "Dr. Rossi's research focuses on numerical linear algebra and its applications in data science.", IsFeatured = true },
            new() { Id = 7, DepartmentId = 2, CourseCode = "MATH305", Title = "Probability & Statistics", Description = "Probability theory, random variables, distributions, hypothesis testing, and regression analysis.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", InstructorName = "Dr. Elena Rossi", InstructorBio = "Dr. Rossi's research focuses on numerical linear algebra and its applications in data science." },
            new() { Id = 8, DepartmentId = 3, CourseCode = "ENG101", Title = "Composition & Rhetoric", Description = "Develop effective academic writing skills through essay composition, rhetorical analysis, and peer review.", Credits = 3, Schedule = "Mon/Wed 9:00–10:20 AM", InstructorName = "Prof. Diana Hart", InstructorBio = "Prof. Hart is a published author and writing coach with expertise in academic and creative writing pedagogy." },
            new() { Id = 9, DepartmentId = 3, CourseCode = "ENG220", Title = "American Literature", Description = "Survey of American literature from the colonial period to the present, examining major authors and literary movements.", Credits = 3, Schedule = "Tue/Thu 2:00–3:20 PM", InstructorName = "Dr. Marcus Johnson", InstructorBio = "Dr. Johnson is a specialist in 20th-century American fiction and has authored two books on the Harlem Renaissance.", IsFeatured = true },
            new() { Id = 10, DepartmentId = 4, CourseCode = "PHYS101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Includes weekly lab sessions with hands-on experiments.", Credits = 4, Schedule = "Mon/Wed/Fri 1:00–1:50 PM + Thu Lab 2:00–4:50 PM", InstructorName = "Dr. Alan Torres", InstructorBio = "Dr. Torres is an experimental physicist whose research involves particle detection and accelerator physics." },
            new() { Id = 11, DepartmentId = 4, CourseCode = "PHYS201", Title = "Electromagnetism", Description = "Electric and magnetic fields, Maxwell's equations, electromagnetic waves, and optics.", Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM + Fri Lab 1:00–3:50 PM", InstructorName = "Dr. Alan Torres", InstructorBio = "Dr. Torres is an experimental physicist whose research involves particle detection and accelerator physics." },
            new() { Id = 12, DepartmentId = 5, CourseCode = "HIST101", Title = "World Civilizations", Description = "A broad survey of world history from ancient civilizations to the modern era, focusing on cultural exchange and conflict.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:20 PM", InstructorName = "Prof. Linda Nguyen", InstructorBio = "Prof. Nguyen is a historian specializing in cross-cultural encounters and global trade networks.", IsFeatured = true },
            new() { Id = 13, DepartmentId = 5, CourseCode = "HIST250", Title = "The Modern Era", Description = "Political, social, and economic transformations from the Industrial Revolution through the 21st century.", Credits = 3, Schedule = "Mon/Wed 3:30–4:50 PM", InstructorName = "Dr. Thomas Wright", InstructorBio = "Dr. Wright studies modern political history with a focus on democratization movements worldwide." },
        };
    }

    public List<Department> GetAllDepartments() => _departments;

    public Department? GetDepartmentById(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetAllCourses() => _courses;

    public List<Course> SearchCourses(string? searchTerm, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
        {
            query = query.Where(c => c.DepartmentId == departmentId.Value);
        }

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.CourseCode.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public Course? GetCourseById(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public bool SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        // In a real application this would persist to a database.
        return GetCourseById(request.CourseId) is not null;
    }
}

