@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CourseCatalogService CatalogService
@rendermode InteractiveServer

<PageTitle>Enrollment Request</PageTitle>

<h1>Submit Enrollment Request</h1>
<p>Fill out the form below to request enrollment in a course.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <strong>Success!</strong> Your enrollment request for <em>@selectedCourseTitle</em> has been submitted.
    </div>
    <a href="courses" class="btn btn-primary">Back to Courses</a>
}
else
{
    <div class="row">
        <div class="col-md-6">
            <EditForm Model="request" OnValidSubmit="HandleSubmit" FormName="enrollment">
                <DataAnnotationsValidator />
                <ValidationSummary class="text-danger" />

                <div class="mb-3">
                    <label for="fullName" class="form-label">Full Name</label>
                    <InputText id="fullName" class="form-control" @bind-Value="request.FullName" />
                    <ValidationMessage For="() => request.FullName" class="text-danger" />
                </div>

                <div class="mb-3">
                    <label for="studentId" class="form-label">Student ID</label>
                    <InputText id="studentId" class="form-control" @bind-Value="request.StudentId" />
                    <ValidationMessage For="() => request.StudentId" class="text-danger" />
                    <div class="form-text">6–10 uppercase alphanumeric characters (e.g., STU12345)</div>
                </div>

                <div class="mb-3">
                    <label for="courseSelect" class="form-label">Course</label>
                    <InputSelect id="courseSelect" class="form-select" @bind-Value="request.CourseId">
                        <option value="0">— Select a course —</option>
                        @foreach (var course in courses)
                        {
                            <option value="@course.Id">@course.CourseCode — @course.Title</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => request.CourseId" class="text-danger" />
                </div>

                <button type="submit" class="btn btn-success">Submit Request</button>
            </EditForm>
        </div>
    </div>
}

@code {
    [SupplyParameterFromQuery] public int? CourseId { get; set; }

    private EnrollmentRequest request = new();
    private List<Course> courses = new();
    private bool submitted;
    private string selectedCourseTitle = string.Empty;

    protected override void OnInitialized()
    {
        courses = CatalogService.GetAllCourses();
        if (CourseId.HasValue)
        {
            request.CourseId = CourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        var success = CatalogService.SubmitEnrollmentRequest(request);
        if (success)
        {
            selectedCourseTitle = courses.FirstOrDefault(c => c.Id == request.CourseId)?.Title ?? "Unknown";
            submitted = true;
        }
    }
}

